-- ── ProductPlan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based product roadmap and product intelligence platform that helps product managers plan, visualize, and communicate strategy across teams.$q$, short_description),
  pricing_model = COALESCE($q$Seat-based subscription billed annually. Pricing is per active editor while viewers who only need to see a shared roadmap are unlimited and free on every plan. Enterprise pricing is custom and quote-based.$q$, pricing_model),
  starting_price = COALESCE($q$From $39 per editor per month (Basic plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Estimated 51-100 employees (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Denver, Colorado, United States (originally founded in Santa Barbara, California)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ProductPlan Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what ProductPlan offers in 2026: roadmap software pricing, key features, pros and cons, and how it compares for product management teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ProductPlan is a cloud-based product roadmap and product intelligence platform founded in 2013 by Jim Semick and Greg Goodman in Santa Barbara, California. The company operated for years without outside venture capital, building a customer base that includes organizations such as Nike, Intuit, NASA, Autodesk, and PBS. ProductPlan is now headquartered in Denver, Colorado, and states it has helped teams create more than 860,000 roadmaps and execute over 23 million strategic initiatives. In 2025, Denver-based private equity firm Bow River Capital acquired a majority stake in ProductPlan, and in 2026 ProductPlan acquired the AI startup Winware.ai, using that acquisition as the foundation for a new Product Intelligence Platform under CEO Steven Cohn, a four-time founder who previously built Winware.ai. The core product lets product managers build drag-and-drop visual roadmaps, timeline and swimlane views, and portfolio views for organizations running multiple roadmaps at once, along with prioritization boards that tie initiatives to strategic goals such as OKRs. The newer Product Intelligence layer adds idea capture, research surveys, and video-call feedback aggregation so customer input can be validated and linked directly to roadmap items, with AI-suggested initiatives surfacing patterns across collected feedback. ProductPlan integrates with tools such as Jira, Azure DevOps, Slack, and Salesforce, and includes risk and dependency tracking plus launch management for coordinating go-to-market timing. Administrative features include single sign-on, advanced admin controls, and white-glove onboarding with dedicated customer success support on higher tiers. Pricing is seat-based and billed annually: organizations only pay for editors who build and manage roadmaps, while viewers are unlimited and included at no extra cost on every plan. Published pricing lists a Basic plan starting around $39 per editor per month and a Professional plan in the $69 to $79 per editor per month range, with Enterprise pricing quoted individually for larger deployments; ProductPlan does not publish a free-forever tier but offers a 14-day free trial. On G2, ProductPlan holds a 4.3 out of 5 rating from more than 200 reviews, with reviewers frequently praising its visual clarity, ease of building executive-ready roadmaps, and drag-and-drop editing, while some reviews note that costs can add up for larger teams of editors and that deeper customization or reporting can require higher-tier plans. The product is aimed primarily at product managers, product marketing teams, and executives who need to align cross-functional stakeholders around a shared strategic plan rather than a granular engineering backlog; teams that need detailed sprint-level task tracking typically pair ProductPlan with a separate delivery tool such as Jira. As of 2026, ProductPlan competes most directly with Productboard, Aha!, and Roadmunk in the dedicated product-roadmap software category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '73f568cf-6fdf-4904-bb21-3fb27cb40d1c';

