-- ── ProfitWell ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free subscription analytics tool that automatically calculates MRR, ARR, churn, and other SaaS metrics, now offered as ProfitWell Metrics inside Paddle's billing and payments platform.$q$, short_description),
  pricing_model = COALESCE($q$ProfitWell Metrics itself is free to use indefinitely. Paddle, the parent company that acquired ProfitWell, charges merchants a percentage-based fee on revenue processed through its merchant-of-record billing platform.$q$, pricing_model),
  starting_price = COALESCE($q$Free (ProfitWell Metrics); Paddle's billing platform fees are transaction-based and quoted per merchant$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Approximately 395-400 employees (Paddle, the parent company, as of 2026)$q$, company_size),
  headquarters = COALESCE($q$Originally Boston, Massachusetts, United States; now operated by Paddle, headquartered in London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ProfitWell Review 2026: Features, Pricing and Paddle Acquisition Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what happened to ProfitWell after its 2022 acquisition by Paddle, how ProfitWell Metrics works today, and whether it still fits your SaaS analytics stack.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ProfitWell was founded in 2012 in Boston by Patrick Campbell, initially operating as a pricing strategy consultancy called Price Intelligently before evolving into a broader subscription-analytics company. Campbell bootstrapped the business for roughly a decade without outside funding, cashing out his 401k to cover initial living expenses, and grew it into a suite of products serving SaaS and subscription businesses: Price Intelligently for pricing strategy and optimization, Retain for automated churn reduction, and ProfitWell Metrics, a free tool that automatically calculates MRR, ARR, churn, LTV, and other core subscription metrics by connecting directly to a company's billing data. In May 2022, payments infrastructure company Paddle acquired ProfitWell for more than 200 million dollars in cash and equity, funded in part by Paddle's own 200 million dollar Series D raise. It was Paddle's first acquisition. As part of the deal, ProfitWell CEO Patrick Campbell became Paddle's Chief Strategy Officer while ProfitWell's chief product officer Facundo Chamut retained his product leadership role, and ProfitWell continued operating under its own brand while the two companies integrated their products through the rest of 2022. As of 2026, ProfitWell Metrics remains available and free to use, rebranded in Paddle's own materials as ProfitWell Metrics by Paddle, and still takes only a few minutes to connect to a company's existing payments stack. It continues to support integrations with Stripe, Chargebee, Braintree, and other billing systems, though Paddle has clearly prioritized the deepest ongoing feature development for merchants who use Paddle Billing as their core payments and subscription-management platform. In practice, ProfitWell today functions less as a standalone company and more as a free analytics and lead-generation layer that sits on top of Paddle's paid merchant-of-record billing product, which handles global payments, tax compliance, subscription billing, and checkout for software companies. Paddle itself is headquartered in London, with roughly 395 to 400 employees globally as of 2026, and has raised over 290 million dollars in funding at a valuation of around 1.4 billion dollars from investors including KKR, FTV Capital, and BGF. For a directory or comparison context, it is important to note that ProfitWell is no longer an independently operated, separately priced SaaS product; the ProfitWell brand and its free Metrics tool now function as an entry point into the Paddle ecosystem, and businesses evaluating it for retention or pricing-optimization capabilities should expect deeper integration with, and eventual migration toward, Paddle's core billing platform rather than a fully separate roadmap.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2a4f0fe3-b308-423c-aecf-cdff842abdcc';

