-- ── ProjectSend ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted file sharing software that lets businesses securely send and receive files with clients through their own server.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source under the GNU GPL v2 license. There are no license fees; the only cost is the hosting infrastructure a user chooses to run it on.$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); users only pay for their own server or hosting, which can start at just a few dollars per month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Open-source community project maintained by volunteer contributors; not a commercial company with a disclosed headcount$q$, company_size),
  headquarters = COALESCE($q$No corporate headquarters (open-source project); originally created by developer Emmanuel B. Muriaga$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Italian$q$, $q$and 60+ additional community-translated languages$q$]::text[],
  seo_title = COALESCE($q$ProjectSend Review 2026: Free Self-Hosted File Sharing Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore ProjectSend, the free open-source self-hosted file sharing tool: features, setup, pricing, pros and cons, and how it compares to paid alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ProjectSend is a free, open-source, self-hosted file sharing application built specifically for businesses that need to exchange files securely with clients rather than the general public. The project traces back to 2012 and was originally created by developer Emmanuel B. Muriaga; it is distributed under the GNU General Public License version 2, meaning the source code is freely available, modifiable, and redistributable, and there are no license fees for using it. Because ProjectSend is self-hosted, organizations install it on their own server, VPS, or shared hosting account (typically running PHP and MySQL/MariaDB), which means the only ongoing cost is whatever hosting infrastructure the organization chooses; budget VPS providers advertise hosting suitable for ProjectSend for just a few dollars per month. The core workflow centers on client relationships: administrators create client accounts or client groups, then upload files that are shared privately with a specific client or group, and optionally allow clients to upload files back into a designated folder. This two-way exchange, combined with role-based permissions for internal staff users, makes it popular with agencies, accountants, consultants, web developers, and any business that regularly exchanges sensitive documents with external clients and wants to avoid relying on third-party cloud storage services. Beyond the core upload and download workflow, ProjectSend includes detailed activity logging that tracks actions taken by both staff users and clients, download tracking, automatic expiration for uploads, email notifications, support for S3-compatible object storage as a backend, and the ability to generate public file links when needed. The interface supports more than 70 languages through community-contributed translations available via Transifex, making it usable for organizations operating outside English-speaking markets. Administrators can customize branding, including logos and color themes, so the portal can be presented to clients as part of the company's own tooling rather than an obviously third-party product. The software is optimized for mobile browsers as well as desktop use. Because it is self-hosted and open source, ProjectSend appeals most to technically capable teams or IT departments that want full control over where client files live, without recurring per-user SaaS fees; the tradeoff is that the organization is responsible for its own hosting, backups, security patching, and uptime, unlike a managed SaaS file-sharing product. Development continues through the projectsend GitHub organization, with releases and translation updates published on projectsend.org. For directory and comparison purposes, ProjectSend competes with self-hosted alternatives like Nextcloud and FileRun, as well as commercial client-portal products like ShareFile and Content Snare, differentiating itself primarily through being fully free, open source, and purpose-built around client file exchange rather than general team collaboration.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7eb54f85-fa53-45b8-9643-952ef361763c';

