-- ── PropelAuth ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Authentication and user management platform built specifically for B2B SaaS products, with organizations, roles, and enterprise SSO as first-class concepts.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription based on monthly active users (MAUs), with a free tier, paid Growth and Growth Plus plans, and custom-quoted Enterprise pricing for larger deployments.$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 10,500 monthly active users; Growth plan starts at $150 per month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Estimated 5-10 employees$q$, company_size),
  headquarters = COALESCE($q$Redwood City, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PropelAuth Review 2026: Features, Pricing and B2B Auth Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how PropelAuth's B2B-focused authentication platform works in 2026, including pricing, SSO and SCIM support, key features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PropelAuth is an authentication and user management platform founded in 2021 and headquartered in Redwood City, California, built by a founding team with prior experience building authentication systems for both enterprise and startup clients across B2B and B2C markets. The company went through Y Combinator's Winter 2022 batch and has raised a total of roughly 3.09 million dollars, including a 2.59 million dollar seed round, from investors including Y Combinator, Tiger Global, 8-Bit Capital, Soma Capital, Flex Capital, Crosstimbers Capital Group, Forward Deployed VC, and individual angel investors. PropelAuth's core positioning is that it is purpose-built for B2B SaaS authentication specifically, rather than being a general-purpose identity platform adapted for B2B use cases after the fact. The defining architectural choice is that organizations are a first-class concept throughout the product: rather than authenticating individual users in isolation, PropelAuth models the reality that most B2B customers are companies with many employees who need different roles and permissions, and a single user account can belong to multiple organizations with different roles in each. Every authenticated request carries the user's organization membership, roles, and permissions, and organizations can be configured to let new users auto-join via a verified company email domain, removing manual invite friction for larger customer accounts. Enterprise-readiness features are deeply integrated into this same organization model rather than bolted on separately: SAML and OIDC single sign-on and SCIM directory provisioning are supported out of the box for identity providers including Okta, Microsoft Entra ID, OneLogin, and JumpCloud, and PropelAuth is explicit that enabling SSO for a customer requires no code changes, since customers can self-configure their own SSO connection through guided setup flows. Additional features include configurable password policies, enforced multi-factor authentication, per-organization session controls, user impersonation for support and debugging (built with safety guardrails and audit alerting), webhook events for user and organization lifecycle actions, a Terraform provider for managing auth configuration as code, and the ability for users and organizations to generate their own API keys that automatically invalidate if the associated user or organization is blocked or deleted. PropelAuth's pricing is structured around monthly active users: a free tier covers up to 10,500 MAUs with unlimited organizations, a Growth plan at 150 dollars per month adds user impersonation, unlimited enterprise SSO connections at no extra per-connection fee, a separate staging environment, and API key management, with additional users beyond the plan's included volume billed incrementally with volume discounts; a Growth Plus plan at 500 dollars per month adds SCIM directory sync and more advanced organization and security controls; and Enterprise customers get custom-quoted pricing and terms. A notable competitive point PropelAuth emphasizes is that all paid plans include unlimited SSO connections with no per-connection fees, which is a meaningful differentiator against some competing identity platforms that charge incrementally per enterprise SSO connection as a customer's B2B customer base grows. As a small, venture-backed team (estimated at fewer than ten employees as of 2026), PropelAuth is best suited to B2B SaaS companies, particularly startups and mid-market software companies, that need enterprise-ready authentication (SSO, SCIM, organizations, RBAC) without building and maintaining it themselves.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '789f97be-c510-457a-8f6f-591187e6b959';

