-- ── Propertybase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Real estate CRM platform built on Salesforce for brokerages and agents, now operated as Propertybase powered by Lone Wolf Technologies.$q$, short_description),
  pricing_model = COALESCE($q$Per-user monthly subscription with a minimum seat commitment for the Salesforce Edition; the separate Propertybase GO product uses custom, quote-based pricing.$q$, pricing_model),
  starting_price = COALESCE($q$From $79 per user per month (Salesforce Edition, 10-user minimum, roughly $790/month minimum)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Approximately 500-750 employees (Lone Wolf Technologies, the parent company)$q$, company_size),
  headquarters = COALESCE($q$Cambridge, Ontario, Canada (Lone Wolf Technologies headquarters); Propertybase originated in West Boxford, Massachusetts, United States and Munich, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Propertybase Review 2026: Features, Pricing and Lone Wolf Ownership Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Propertybase's Salesforce-based real estate CRM works in 2026 under Lone Wolf Technologies ownership, including pricing, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Propertybase is a real estate customer relationship management platform founded in 2010 that has gone through multiple rounds of acquisition on its way to becoming part of Lone Wolf Technologies, one of the largest real estate technology companies in North America. Munich-based Propertybase GmbH was originally acquired by US firm Boston Logic in June 2017, and then in August 2021 Lone Wolf Technologies, a Vista Equity Partners portfolio company, acquired Propertybase outright, describing the deal as completing real estate's technology platform for agents and brokers by combining Propertybase's CRM and marketing capabilities with Lone Wolf's existing transaction management and back-office software. Today the product is marketed as Propertybase powered by Lone Wolf and comes in two distinct editions: Propertybase GO, a CRM and website solution aimed at brokerages and teams with simplified setup and quote-based pricing, and Propertybase Salesforce Edition, an enterprise-class CRM built natively on the Salesforce platform for larger brokerages that want deep customization and Salesforce's full reporting and workflow ecosystem. The Salesforce Edition requires a minimum of 10 user licenses at 79 dollars per user per month, which includes the underlying Force.com platform license, putting the practical minimum entry cost at around 790 dollars per month, billed monthly, quarterly, or annually depending on the contract. Core capabilities span the real estate transaction lifecycle: IDX and MLS-integrated websites with real-time listing synchronization for lead capture, automated lead routing and matching using round robin, auto-assign, or click-to-claim rules, integrated email marketing with segmentation and drip automation for nurture sequences and transaction-milestone communications, transaction management integration tying into Lone Wolf's broader back-office and transaction software, and reporting and analytics that range from pipeline and agent performance reports up to full custom Salesforce dashboards on the Salesforce Edition. Mobile apps for iOS and Android provide contact management, activity logging, calendar sync, and deal pipeline visibility for agents working in the field. Lone Wolf Technologies, the parent company, is headquartered in Cambridge, Ontario, Canada, with a significant presence in Dallas, Texas, and reported employee counts across sources ranging from roughly 500 to nearly 750 people as of 2025, reflecting a company that has grown substantially through acquisitions across more than 30 years in the real estate software industry under Vista Equity Partners ownership. Given its Salesforce-native architecture, per-seat pricing, and minimum user requirements, Propertybase Salesforce Edition is positioned primarily toward mid-size and larger real estate brokerages that already value or use the Salesforce ecosystem and need deep CRM customization, while smaller teams and independent brokerages are more likely to be steered toward the simplified Propertybase GO product or Lone Wolf's other, less complex offerings.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '37206632-9f9a-460f-8492-df6a397cf34f';

