INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Drag-and-drop roadmap builder$q$, $q$Build timeline, swimlane, and Gantt-style roadmap views without spreadsheets, and rearrange initiatives visually as priorities shift.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Portfolio views$q$, $q$Roll up multiple team or product-line roadmaps into a single portfolio view for leadership visibility across the organization.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Prioritization boards$q$, $q$Score and rank initiatives against custom criteria so teams can defend roadmap decisions with data rather than opinion.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$OKR integration$q$, $q$Link roadmap initiatives directly to company objectives and key results to show how day-to-day work ladders up to strategy.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Product Intelligence feedback capture$q$, $q$Collect ideas, run research surveys, and pull insights from recorded customer calls, then validate opportunities before committing roadmap space.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$AI-suggested initiatives$q$, $q$Surface patterns across captured feedback and research to recommend candidate roadmap initiatives automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Risk, dependency, and launch management$q$, $q$Track cross-team dependencies and coordinate go-to-market launch timing alongside the roadmap itself.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Enterprise administration$q$, $q$Single sign-on, advanced admin permissions, and white-glove onboarding are available for larger deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Purpose-built for roadmapping, with a cleaner and faster learning curve than general-purpose project tools repurposed for roadmaps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Unlimited free viewers on every plan makes it easy to share roadmaps broadly across an organization$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Strong visual polish that produces executive-ready roadmap presentations with minimal formatting work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Solid third-party integrations with Jira, Azure DevOps, Slack, and Salesforce for connecting roadmaps to delivery work$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$No permanent free tier, only a 14-day trial, so evaluating long-term fit requires a time-boxed test$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Seat-based editor pricing can get expensive as more product managers and stakeholders need edit access$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Not a replacement for sprint-level task tracking, so many teams still need a separate delivery tool alongside it$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Recent ownership changes (2025 majority acquisition, 2026 Winware.ai acquisition) mean the product roadmap and pricing structure could continue to evolve$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$What is ProductPlan used for$q$, $q$ProductPlan is used by product managers and product teams to build, visualize, and share strategic product roadmaps, prioritize initiatives, and align stakeholders around company objectives.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$How much does ProductPlan cost$q$, $q$ProductPlan's published Basic plan starts around $39 per editor per month billed annually, with a Professional plan in the $69 to $79 per editor per month range and custom Enterprise pricing for larger teams. Viewers are unlimited and free on every plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Does ProductPlan offer a free plan$q$, $q$ProductPlan does not offer a permanent free plan, but it does offer a 14-day free trial so teams can evaluate the product before committing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Who owns ProductPlan$q$, $q$ProductPlan was founded in 2013 by Jim Semick and Greg Goodman. In 2025, Denver-based private equity firm Bow River Capital acquired a majority stake in the company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Is ProductPlan good for engineering task management$q$, $q$No. ProductPlan is focused on strategic roadmapping rather than sprint-level task or ticket management, so most engineering teams pair it with a tool like Jira for day-to-day delivery work.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$What is ProductPlan's Product Intelligence Platform$q$, $q$Launched in 2026 following the acquisition of AI startup Winware.ai, the Product Intelligence Platform adds feedback capture, research surveys, and AI-suggested initiatives on top of ProductPlan's existing roadmapping tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$What integrations does ProductPlan support$q$, $q$ProductPlan integrates with tools including Jira, Azure DevOps, Slack, and Salesforce, among others, to connect roadmap planning with delivery and CRM systems.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$What is ProductPlan's G2 rating$q$, $q$ProductPlan holds a 4.3 out of 5 rating on G2 based on more than 200 reviews, with users highlighting its visual clarity and ease of use.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Cross-functional roadmap alignment$q$, $q$Product leaders build a single visual roadmap that engineering, sales, marketing, and executives can all view without needing edit access.$q$, $q$Product managers and VPs of Product at mid-size to enterprise software companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Portfolio-level planning$q$, $q$Organizations running multiple products or teams use portfolio views to compare and coordinate roadmaps across the whole product line.$q$, $q$Heads of Product and product operations teams managing several product lines$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Customer feedback-driven prioritization$q$, $q$Teams capture ideas and research directly in the platform and use AI-suggested initiatives to translate validated customer feedback into prioritized roadmap items.$q$, $q$Product managers focused on discovery and customer-driven roadmap prioritization$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Basic$q$, $q$From $39 per editor/month$q$, $q$Annual$q$, NULL, $q$["Unlimited viewers","Roadmap and portfolio views","Prioritization boards","Integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Professional$q$, $q$Approximately $69 to $79 per editor/month$q$, $q$Annual$q$, NULL, $q$["Everything in Basic","OKR integration","Risk and dependency tracking","Launch management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual$q$, NULL, $q$["Everything in Professional","Single sign-on","Advanced admin management","White-glove onboarding and dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProductPlan is a purpose-built roadmapping platform for product managers who need to turn strategy into a visual, shareable plan. Founded in 2013 and now headquartered in Denver, Colorado, the company has spent over a decade focused specifically on the roadmapping category, rather than trying to be a full project management or engineering ticketing system.$q$, $q$Since its 2025 majority acquisition by Bow River Capital and its 2026 acquisition of Winware.ai, ProductPlan has pushed beyond static roadmap visuals into a broader Product Intelligence Platform that connects customer feedback, research, and AI-suggested initiatives directly to the roadmap itself.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, ProductPlan offers drag-and-drop roadmap building, timeline and swimlane views, and portfolio views that let leadership see multiple team roadmaps in one place. Prioritization boards allow teams to score and rank initiatives, and dedicated OKR functionality ties day-to-day roadmap items back to company-level objectives.$q$, $q$Newer Product Intelligence features include idea capture forms, research surveys, and the ability to pull feedback straight from recorded video calls, all of which feed into an opportunity-validation workflow. Risk and dependency tracking, launch management, and integrations with Jira, Azure DevOps, Slack, and Salesforce round out the platform for teams coordinating roadmap work with delivery teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73f568cf-6fdf-4904-bb21-3fb27cb40d1c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ProductPlan uses seat-based, annually billed pricing where only editors (people who build and manage roadmaps) count toward the seat total; viewers who are shared a roadmap link are unlimited and free on every plan. This structure is meant to encourage broad internal visibility without penalizing companies for sharing roadmaps widely.$q$, $q$Published plans start with a Basic tier around $39 per editor per month, a Professional tier in the $69 to $79 per editor per month range, and a custom-quoted Enterprise tier for larger organizations that need SSO, advanced admin controls, and dedicated onboarding. There is no permanent free plan, but a 14-day free trial is available.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Automated MRR and ARR tracking$q$, $q$Automatically calculates monthly and annual recurring revenue directly from connected billing data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Churn and retention reporting$q$, $q$Tracks customer and revenue churn over time to help SaaS teams spot retention problems early.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Customer lifetime value (LTV) calculation$q$, $q$Estimates LTV automatically based on historical subscription and payment data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Multi-processor billing integrations$q$, $q$Connects with Stripe, Chargebee, Braintree, Paddle Billing, and other payment processors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Benchmarking data$q$, $q$Historically provided benchmark comparisons against other SaaS companies using aggregated, anonymized ProfitWell data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Retain churn-recovery tooling$q$, $q$Automated dunning and failed-payment recovery capability, now offered as part of Paddle's broader product and services suite.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Core metrics dashboard remains genuinely free with no credit card required to start$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Quick setup that connects directly to existing billing and payment data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Backed by Paddle's larger, well-funded payments infrastructure and engineering team$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Useful benchmarking heritage from years of aggregated SaaS metrics data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$No longer an independently operated product roadmap; direction is now set by Paddle's priorities$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Deepest ongoing feature development is increasingly oriented toward companies using Paddle Billing specifically$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Some previously distinct ProfitWell products (Retain, Price Intelligently) have been absorbed into Paddle's broader offering rather than sold as standalone tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Companies not using or considering Paddle as their billing provider may find long-term support and roadmap commitment less certain$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Is ProfitWell still a separate company$q$, $q$No. Paddle acquired ProfitWell in May 2022 for more than 200 million dollars, and ProfitWell now operates as ProfitWell Metrics within the Paddle product ecosystem.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Is ProfitWell Metrics still free$q$, $q$Yes, ProfitWell Metrics remains free to use as of 2026, automatically calculating MRR, ARR, churn, and LTV from a company's connected billing data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$What happened to ProfitWell's Retain and Price Intelligently products$q$, $q$Retain (churn reduction) and Price Intelligently (pricing strategy) were part of the original ProfitWell suite and have been integrated into Paddle's broader product and services offering since the 2022 acquisition.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Does ProfitWell Metrics work with Stripe$q$, $q$Yes, ProfitWell Metrics integrates with Stripe as well as Chargebee, Braintree, Paddle Billing, and other common billing and payment processors.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Who founded ProfitWell$q$, $q$ProfitWell was founded in 2012 by Patrick Campbell in Boston, originally as a pricing consultancy called Price Intelligently.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$What is Patrick Campbell's role today$q$, $q$After the acquisition, ProfitWell founder and CEO Patrick Campbell became Paddle's Chief Strategy Officer.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$How much did Paddle pay for ProfitWell$q$, $q$Paddle acquired ProfitWell in May 2022 for more than 200 million dollars in cash and equity, funded in part by Paddle's 200 million dollar Series D round.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Should I use ProfitWell if I do not use Paddle for billing$q$, $q$ProfitWell Metrics still integrates with non-Paddle processors like Stripe, Chargebee, and Braintree, so it can be used independently of Paddle Billing, though Paddle's newest features are generally built first for its own billing customers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Free SaaS metrics dashboard$q$, $q$Early-stage and growth SaaS companies connect their billing data to automatically track MRR, ARR, and churn without building internal reporting.$q$, $q$Founders and finance teams at subscription businesses that want free, automated recurring-revenue reporting$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Churn and retention monitoring$q$, $q$Revenue and customer-success teams use ProfitWell's metrics and historical Retain capabilities to monitor and reduce involuntary and voluntary churn.$q$, $q$Customer success and RevOps teams at subscription companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Evaluating Paddle as a billing provider$q$, $q$Companies exploring merchant-of-record billing test ProfitWell Metrics as a free entry point before adopting Paddle's full payments and subscription platform.$q$, $q$SaaS companies evaluating a switch to a merchant-of-record billing provider$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$ProfitWell Metrics$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Automated MRR and ARR tracking","Churn reporting","LTV calculation","Integrations with Stripe, Chargebee, Braintree, and Paddle Billing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$Paddle Billing (parent platform)$q$, $q$Percentage-based transaction fee, quoted per merchant$q$, $q$Usage-based$q$, NULL, $q$["Merchant-of-record global payments","Tax and compliance handling","Subscription billing and checkout","Access to ProfitWell Metrics and retention tooling"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProfitWell began in 2012 as Price Intelligently, a Boston-based pricing consultancy founded by Patrick Campbell, before evolving into a full subscription-analytics company known for its free MRR, ARR, and churn-tracking product. After roughly a decade of bootstrapped growth, Paddle acquired ProfitWell in May 2022 for more than 200 million dollars.$q$, $q$Today, ProfitWell operates as ProfitWell Metrics within the Paddle ecosystem. The free metrics dashboard remains available on its own, but the deepest product investment and integration now flows through Paddle's broader payments and subscription billing platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ProfitWell Metrics connects to a company's existing billing data (Stripe, Chargebee, Braintree, Paddle Billing, and others) and automatically calculates core subscription metrics including MRR, ARR, churn rate, LTV, and customer counts, without requiring manual spreadsheet work.$q$, $q$Historically, the broader ProfitWell suite also included Retain, an automated churn-reduction tool for recovering failed payments, and Price Intelligently, a pricing strategy service; both capabilities have been folded into Paddle's product and services offering since the acquisition.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a4f0fe3-b308-423c-aecf-cdff842abdcc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ProfitWell Metrics itself remains free to use, with setup that Paddle describes as taking only a few minutes once a billing integration is connected. There is no paid tier for the core metrics dashboard.$q$, $q$Because ProfitWell is now part of Paddle, the meaningful pricing consideration for most businesses is Paddle's own merchant-of-record billing platform, which charges a percentage-based fee on transactions it processes rather than a flat subscription price.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Client and client-group accounts$q$, $q$Create individual client logins or group clients together to control exactly who can see which shared files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Two-way file exchange$q$, $q$Allow clients not just to download files but also to upload files back into a folder assigned specifically to them.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Role-based staff permissions$q$, $q$Assign different access levels to internal team members so not everyone has full administrative control.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Activity logging and download tracking$q$, $q$Every upload, download, and administrative action is logged, giving a full audit trail of file activity.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Automatic upload expiration$q$, $q$Set files to automatically expire after a defined period, useful for time-sensitive document sharing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$S3-compatible storage support$q$, $q$Store files on S3-compatible object storage instead of, or alongside, local server storage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Custom branding and themes$q$, $q$White-label the client portal with your own logo and color scheme so it feels like part of your own product.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$70-plus language translations$q$, $q$The interface is available in more than 70 languages thanks to community-contributed translations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Completely free and open source with no per-user or per-feature license costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Full control over data since files are stored on infrastructure the organization owns$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Purpose-built two-way client file exchange rather than generic team file storage$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Extensive language support makes it usable well beyond English-speaking markets$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Requires self-hosting, so the organization is responsible for server setup, security patching, and backups$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$No official managed cloud version, unlike SaaS competitors that handle infrastructure for you$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Interface and feature set are more utilitarian than modern SaaS client-portal products$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Support relies on community documentation and forums rather than a dedicated commercial support team$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Is ProjectSend really free$q$, $q$Yes, ProjectSend is completely free and open source under the GNU GPL v2 license, with no license fees. The only cost is the hosting infrastructure you run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Do I need technical skills to install ProjectSend$q$, $q$Yes, some technical knowledge is helpful since ProjectSend is self-hosted and typically requires a server running PHP and a MySQL or MariaDB database, though many hosting providers offer one-click installers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Can clients upload files, not just download them$q$, $q$Yes, ProjectSend supports two-way file exchange, so administrators can allow specific clients to upload files into a folder assigned only to them.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$How many languages does ProjectSend support$q$, $q$ProjectSend's interface is available in more than 70 languages through community-contributed translations distributed via Transifex.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Who created ProjectSend$q$, $q$ProjectSend was originally created by developer Emmanuel B. Muriaga, with the project dating back to 2012 and continuing today as an open-source community project.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Does ProjectSend support cloud storage backends$q$, $q$Yes, in addition to local server storage, ProjectSend supports S3-compatible object storage.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Is ProjectSend a good alternative to Dropbox or Google Drive for client file sharing$q$, $q$For businesses that want a self-hosted, client-focused portal with full data control and no per-user fees, ProjectSend is a common open-source alternative, though it lacks the polish and real-time collaboration features of consumer cloud storage tools.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Can I customize ProjectSend's branding$q$, $q$Yes, ProjectSend supports custom branding and themes so the client portal can be presented under your own company's look and feel.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Agency and consultancy client file exchange$q$, $q$Agencies and consultants use ProjectSend to securely send deliverables to clients and receive source files or feedback documents back, all under their own branding.$q$, $q$Marketing agencies, design studios, and independent consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Accounting and professional services document sharing$q$, $q$Firms that handle sensitive financial or legal documents use ProjectSend's self-hosted model to keep client files on infrastructure they control rather than third-party cloud storage.$q$, $q$Accounting firms, law firms, and other regulated professional services$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Internal IT-managed client portal$q$, $q$IT departments deploy ProjectSend as a lightweight, no-license-fee client portal integrated into existing server infrastructure and backup processes.$q$, $q$IT teams at small and mid-size businesses that prefer self-hosted software$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A (one-time install, self-hosted)$q$, NULL, $q$["Full source code and unlimited installs","Client and client-group management","Two-way file exchange","Activity logging and download tracking","70+ language translations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProjectSend is a free, open-source PHP application that businesses install on their own server to share and receive files with clients securely. It dates back to 2012 and was originally created by developer Emmanuel B. Muriaga, and it is released under the GNU GPL v2 license, meaning anyone can use, inspect, and modify the code at no cost.$q$, $q$Unlike consumer cloud storage tools, ProjectSend is purpose-built around client relationships: administrators create client accounts or groups and control exactly which files each client can see, download, or upload, all from infrastructure the organization fully controls.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include client and client-group management, role-based permissions for internal staff, two-way file exchange (clients can be allowed to upload as well as download), detailed activity logging, download tracking, and automatic upload expiration.$q$, $q$The platform also supports S3-compatible object storage as a backend, custom branding and themes so the portal can match a company's own look and feel, mobile-optimized browsing, and an interface translated into more than 70 languages through community contributions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ProjectSend itself carries no license or subscription fee; it is entirely free and open source under GPL v2. There is no tiered pricing, feature gating, or user-count limit built into the software itself.$q$, $q$The only real cost is hosting: since ProjectSend is self-hosted, an organization needs a server or VPS capable of running PHP and a MySQL/MariaDB database, with basic hosting for small deployments available from various providers for just a few dollars per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7eb54f85-fa53-45b8-9643-952ef361763c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Pull-based metrics scraping$q$, $q$The Prometheus server actively pulls metrics from configured targets on a schedule, well suited to dynamic and containerized infrastructure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Built-in time-series database$q$, $q$Metrics are stored efficiently in a purpose-built local time-series database optimized for monitoring workloads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$PromQL query language$q$, $q$A powerful functional query language for filtering, aggregating, and performing calculations across collected time-series data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Client libraries$q$, $q$Official libraries let developers instrument their own application code to expose custom metrics directly to Prometheus.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Exporter ecosystem$q$, $q$A large catalog of exporters translates metrics from third-party systems, such as databases, web servers, and hosts, into Prometheus format.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Alertmanager$q$, $q$A dedicated component handles deduplication, grouping, routing, and silencing of alerts fired from Prometheus rules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Kubernetes-native service discovery$q$, $q$Prometheus can automatically discover scrape targets in dynamic environments like Kubernetes without manual configuration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$CNCF-graduated governance$q$, $q$As a graduated CNCF project, Prometheus follows documented governance and maturity standards with broad community and vendor backing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Completely free and open source with no licensing costs or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$De facto standard for Kubernetes and cloud-native monitoring with a massive ecosystem of exporters and integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Powerful, purpose-built PromQL query language for flexible metrics analysis$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Backed by CNCF graduated-project governance, meaning long-term project stability and broad community support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Requires self-hosting and operational expertise to run and scale reliably at production volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Local storage is not designed for very long-term retention without additional remote-storage or federation setup$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$No official vendor support or SLA included, since it is a community-governed open-source project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Learning PromQL and designing effective alerting rules has a real learning curve for teams new to metrics-based monitoring$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Is Prometheus free to use$q$, $q$Yes, Prometheus is completely free and open source, released under the Apache License 2.0, with no licensing fees or usage limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Who created Prometheus$q$, $q$Prometheus originated at SoundCloud in 2012 to address internal infrastructure-monitoring needs, and was later contributed to the Cloud Native Computing Foundation in 2016.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Is Prometheus a CNCF graduated project$q$, $q$Yes, Prometheus became the second project to reach CNCF's graduated status in August 2018, following Kubernetes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$What query language does Prometheus use$q$, $q$Prometheus uses PromQL, its own functional query language designed for filtering, aggregating, and performing calculations on time-series metrics data.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Does Prometheus handle alerting$q$, $q$Prometheus evaluates alerting rules and fires alerts, and a separate component called Alertmanager handles deduplication, grouping, routing, and silencing of those alerts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Is Prometheus good for Kubernetes monitoring$q$, $q$Yes, Prometheus's pull-based scraping and native service discovery make it one of the most widely used monitoring systems for Kubernetes and other cloud-native environments.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Does Prometheus require a company or license to use commercially$q$, $q$No, Prometheus can be used, modified, and deployed commercially at no cost under the Apache License 2.0, since it has no owning company or commercial license requirement.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$What are Prometheus exporters$q$, $q$Exporters are small adapter applications that translate metrics from third-party systems, like MySQL, PostgreSQL, Redis, or NGINX, into the Prometheus metrics format so they can be scraped and monitored.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Kubernetes and container monitoring$q$, $q$Platform and SRE teams use Prometheus to automatically discover and monitor dynamic Kubernetes workloads, pods, and nodes at scale.$q$, $q$SRE and platform engineering teams running containerized infrastructure$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Application performance metrics$q$, $q$Development teams instrument their own services with Prometheus client libraries to expose custom business and performance metrics for monitoring.$q$, $q$Backend engineering teams building instrumented, observable services$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Infrastructure and alerting pipelines$q$, $q$Operations teams pair Prometheus with Alertmanager and Grafana to build end-to-end infrastructure monitoring and on-call alerting pipelines.$q$, $q$DevOps and infrastructure teams building self-hosted observability stacks$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$Open Source Prometheus$q$, $q$Free$q$, $q$N/A (self-hosted, open source)$q$, NULL, $q$["Full monitoring and alerting toolkit","PromQL query language","Exporter ecosystem","Alertmanager integration","Apache License 2.0"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Prometheus is an open-source monitoring system and time-series database that originated at SoundCloud in 2012 to solve internal infrastructure-monitoring needs, and was later contributed to the Cloud Native Computing Foundation (CNCF) in 2016 as its second hosted project after Kubernetes. It graduated to CNCF's highest maturity tier in 2018.$q$, $q$There is no company behind Prometheus in the traditional sense; it is maintained by a large open-source community under CNCF governance, and released under the permissive Apache License 2.0, making it free to use, self-host, and modify for any purpose.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Prometheus uses a pull-based scraping model, where the Prometheus server actively collects metrics from configured targets at regular intervals, which fits naturally with dynamic, containerized infrastructure such as Kubernetes clusters. Collected data is stored in an efficient built-in time-series database and queried using PromQL, Prometheus's own powerful query language for filtering and aggregating metrics.$q$, $q$The ecosystem includes client libraries for instrumenting custom application code, and a large catalog of exporters that translate metrics from existing systems like databases, web servers, and operating systems into Prometheus's format. A separate Alertmanager component handles deduplication, grouping, and routing of fired alerts to the right notification channels.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Prometheus itself is completely free, with no licensing cost, usage limits, or paid tiers, since it is open-source software released under the Apache License 2.0.$q$, $q$Organizations that want a managed experience rather than operating Prometheus themselves can pay third-party vendors for managed or Prometheus-compatible hosted monitoring services, but that is a separate commercial layer, not something Prometheus or CNCF sells directly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('898eb43f-2596-446a-a7b5-ae0add35bd12', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Prompt registry with version control$q$, $q$Store prompts as versioned, deployable artifacts with commit messages and diffs, similar to how source code is managed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Visual no-code prompt editor$q$, $q$Let non-engineering stakeholders edit, test, and compare prompt variations without developer involvement for every change.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Model comparison and A/B testing$q$, $q$Run the same prompt against multiple models or prompt variants to compare quality, cost, and latency side by side.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Evaluation and regression testing$q$, $q$Schedule recurring regression tests and run batch evaluations against historical usage data to catch quality drift before it reaches users.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Agent versioning$q$, $q$Automatically track configuration changes to AI agents over time, keeping a stable production version while enabling safe experimentation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Tracing and cost visibility$q$, $q$Trace requests through prompts and agents with visibility into usage volume and cost at each step.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Enterprise compliance and self-hosting$q$, $q$HIPAA, SOC 2, GDPR, and CCPA support, along with self-hosted deployment on GCP, AWS, or Azure for regulated or data-sensitive customers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Role-based access control and webhooks$q$, $q$Enterprise-tier access controls and webhook events for integrating prompt and agent lifecycle events into other systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Dedicated, registry-first approach to prompt versioning that is stronger than general-purpose LLM frameworks bolted onto observability$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Permanent free tier makes it accessible for individual developers and small projects to start immediately$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$No-code visual editor genuinely opens prompt iteration up to non-engineering team members$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Enterprise-grade compliance and self-hosting options exist for regulated industries despite being a relatively small company$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Free tier's request and storage caps are fairly modest for anything beyond light individual use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Team plan's roughly 25-user cap can force fast-growing teams into custom Enterprise pricing sooner than expected$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$As a smaller, newer company, long-term roadmap stability is less proven than larger, more established observability vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Primarily focused on prompts and agent versioning rather than being a full end-to-end LLM application development framework$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$What does PromptLayer do$q$, $q$PromptLayer is an LLM engineering platform for managing, versioning, evaluating, and monitoring prompts and AI agents used in production applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Does PromptLayer have a free plan$q$, $q$Yes, PromptLayer offers a permanent free tier for individual developers with a capped monthly request volume, 7-day log retention, and limited storage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$How much does PromptLayer cost$q$, $q$PromptLayer's Pro plan starts at 49 dollars per month, with a Team plan around 500 dollars per month and custom Enterprise pricing for larger organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Who founded PromptLayer$q$, $q$PromptLayer was founded in 2021 by Jonathan Pedoeem and Jared Zoneraich and is headquartered in New York City.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Can non-technical team members use PromptLayer$q$, $q$Yes, PromptLayer includes a visual, no-code prompt editor designed to let non-engineering stakeholders propose and test prompt changes directly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Does PromptLayer support AI agents, not just prompts$q$, $q$Yes, PromptLayer extends its versioning and tracing capabilities to AI agents, automatically tracking configuration changes over time.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Does PromptLayer offer self-hosting$q$, $q$Yes, Enterprise customers can choose self-hosted deployment on GCP, AWS, or Azure, or single-tenant and EU-hosted cloud options.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$How much funding has PromptLayer raised$q$, $q$PromptLayer announced a 5 million dollar seed funding round in February 2025 led by ScOp VC and Stellation Capital, with participation from several notable AI-industry angel investors.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Production prompt version control$q$, $q$Engineering teams use PromptLayer's registry to version prompts, roll back bad changes, and safely deploy new prompt versions without redeploying application code.$q$, $q$AI engineers and backend teams shipping LLM-powered features$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Cross-functional prompt collaboration$q$, $q$Product managers and domain experts use the no-code visual editor to test and refine prompts directly, reducing the back-and-forth with engineering.$q$, $q$Product managers and subject-matter experts working alongside AI engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Agent quality monitoring$q$, $q$Teams building multi-step AI agents use PromptLayer's agent versioning and tracing to monitor cost, usage, and quality drift in production.$q$, $q$AI platform teams operating production LLM agents at scale$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["7-day log retention","2,500 monthly request cap","10 MB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Pro$q$, $q$From $49/month$q$, $q$Monthly$q$, NULL, $q$["Higher request limits","Extended log retention","Team collaboration features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Team$q$, $q$Around $500/month$q$, $q$Monthly$q$, NULL, $q$["Up to approximately 25 users","Expanded evaluation and tracing tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual$q$, NULL, $q$["HIPAA, SOC 2, GDPR, and CCPA compliance","Role-based access control","Self-hosted or single-tenant deployment","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PromptLayer is a New York-based LLM engineering platform founded in 2021 by Jonathan Pedoeem and Jared Zoneraich, built to help engineering and product teams manage prompts and AI agents the way software teams manage code: with versioning, testing, and observability rather than hardcoded strings scattered across an application.$q$, $q$The company raised a 5 million dollar seed round in February 2025 from investors including ScOp VC, Stellation Capital, and notable AI-industry angels, and has positioned itself as a registry-first platform focused specifically on making prompt and agent changes auditable, testable, and safely deployable.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of the platform is a prompt registry with immutable version history, commit messages, and diffs, plus the ability to label a specific version for production use without redeploying application code. A visual, no-code editor lets non-technical stakeholders propose and test prompt changes directly.$q$, $q$PromptLayer also supports evaluation workflows (comparing models, scheduling regression tests, running batch evaluations against historical data), tracing with usage and cost visibility, and dedicated agent versioning that tracks configuration changes over time so teams can experiment without destabilizing production agents.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('788da3e1-d1d6-401e-a948-5529f931152a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PromptLayer offers a permanent free tier for individual developers with a capped monthly request volume, limited log retention, and modest storage, alongside a Pro plan starting at 49 dollars per month for small teams.$q$, $q$A Team plan priced around 500 dollars per month adds a roughly 25-user cap, while Enterprise customers get custom pricing with compliance certifications, role-based access control, and flexible deployment options including self-hosting on major cloud providers or single-tenant and EU-hosted cloud environments.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Flat-rate unlimited-user pricing$q$, $q$Pay one fixed monthly price regardless of how many team members, clients, or contractors need access.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Multiple task views$q$, $q$Manage work using Kanban boards, Gantt-style timeline views, table views, and calendars depending on team preference.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Online proofing and file review$q$, $q$Review, annotate, and approve images, PDFs, and other creative files directly within the platform without switching tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Built-in time tracking$q$, $q$Track billable and non-billable time against tasks and projects natively, without a separate time-tracking app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Custom workflows and statuses$q$, $q$Define custom task statuses and workflow stages to match how each team actually works.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Group chat and discussions$q$, $q$Built-in team messaging and threaded discussions reduce the need for a separate communication tool.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Centralized file storage$q$, $q$Store and share project files in one place, tied directly to related tasks and discussions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Reporting dashboards$q$, $q$Get visibility into project progress, resource workload, and time spent across the organization.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Flat-rate pricing with unlimited users can be significantly cheaper than per-seat competitors for larger teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Combines task management, time tracking, proofing, and chat in one platform, reducing tool sprawl$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Built-in proofing tool is a genuine differentiator for agencies managing creative client approvals$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$No long-term contracts required, with cancel-anytime flexibility and a no-credit-card-required free trial$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Interface and feature depth can feel less modern or polished compared to newer competitors like ClickUp or monday.com$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Fewer native third-party integrations than larger project management platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Advanced workflow customization and higher storage limits require the pricier Ultimate Control plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$As a smaller, privately held company, release cadence and roadmap transparency are less publicly documented than larger competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$How is ProofHub priced$q$, $q$ProofHub uses flat-rate pricing rather than per-user pricing. The Essential plan is 45 dollars per month and the Ultimate Control plan is priced from around 89 dollars per month initially rising to about 150 dollars per month, both including unlimited users.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Does ProofHub charge per user$q$, $q$No, ProofHub is one of the few project management tools that charges a single flat monthly fee covering unlimited users rather than charging per seat.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Who founded ProofHub$q$, $q$ProofHub was founded in 2012 by Sandeep Kashyap, who remains the company's CEO.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Does ProofHub offer a free trial$q$, $q$Yes, ProofHub offers a free trial with unlimited projects and no credit card required.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$What is ProofHub's proofing feature$q$, $q$ProofHub includes a built-in online proofing tool that lets teams review, mark up, and approve images, PDFs, and other files directly within the platform, popular with creative and marketing teams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Where is ProofHub headquartered$q$, $q$ProofHub is headquartered in Covina, California, with a significant operations office in Chandigarh, India.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Is ProofHub good for agencies$q$, $q$Yes, ProofHub's flat-rate pricing and built-in proofing tools make it a popular choice for marketing and creative agencies that need to include many external clients without extra per-seat costs.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Can I cancel ProofHub anytime$q$, $q$Yes, ProofHub does not require long-term contracts and can be cancelled at any time.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Agency client collaboration and approvals$q$, $q$Creative and marketing agencies use ProofHub's proofing tools and flat-rate unlimited-user pricing to collaborate with clients on file reviews and approvals without extra per-seat costs.$q$, $q$Marketing agencies and creative studios working with external clients$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Small business all-in-one project management$q$, $q$Small and mid-size businesses consolidate task management, time tracking, chat, and file storage into ProofHub instead of paying for multiple separate tools.$q$, $q$Small and mid-size business teams wanting one unified collaboration platform$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Large teams needing predictable costs$q$, $q$Organizations with many team members, contractors, or external collaborators use ProofHub's flat pricing to avoid unpredictable per-seat cost growth as headcount increases.$q$, $q$Growing teams and organizations with large or fluctuating headcounts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Essential$q$, $q$$45/month$q$, $q$Monthly or annual (flat rate)$q$, NULL, $q$["Unlimited users","40 projects","15 GB storage","Task management, chat, and time tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$Ultimate Control$q$, $q$From approximately $89/month (introductory), standard rate near $150/month$q$, $q$Monthly or annual (flat rate)$q$, NULL, $q$["Unlimited users","Unlimited projects","More storage","Advanced workflow customization"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProofHub is a project management and team collaboration platform founded in 2012 by Sandeep Kashyap, who still leads the company as CEO today. Headquartered in Covina, California, with a significant operations presence in Chandigarh, India, ProofHub has grown as a privately held, largely bootstrapped business serving tens of thousands of customers.$q$, $q$What sets ProofHub apart from most competitors in the crowded project management category is its flat-rate pricing: instead of charging per user, ProofHub charges one fixed monthly fee that covers unlimited team members, clients, and contractors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ProofHub combines task management across multiple views (including Kanban boards, Gantt-style timelines, and calendars) with time tracking, custom workflows and statuses, and built-in group chat and discussions, so many teams can avoid paying for separate messaging or time-tracking tools.$q$, $q$A standout feature is ProofHub's online proofing tool, which lets teams review, annotate, and approve creative files like images, PDFs, and documents directly within the platform, a workflow that is especially valuable for marketing and creative agencies managing client approvals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2160b497-eee0-445d-8e03-8e017410723b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ProofHub offers two flat-rate plans, both including unlimited users: the Essential plan at 45 dollars per month (40 projects, 15 GB storage), and the Ultimate Control plan, which unlocks unlimited projects and more storage, priced from around 89 dollars per month for new customers before increasing to a standard rate near 150 dollars per month.$q$, $q$Because pricing is flat rather than per seat, ProofHub can be substantially less expensive than per-user competitors for larger teams or organizations that need to include many external collaborators. A free trial with unlimited projects and no credit card requirement is available before committing to a paid plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Organizations as a first-class concept$q$, $q$Model B2B customers as organizations with multiple users, each holding different roles per organization they belong to.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$SAML and OIDC single sign-on$q$, $q$Support enterprise SSO for providers like Okta, Microsoft Entra ID, OneLogin, and JumpCloud with no code changes required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$SCIM directory provisioning$q$, $q$Sync user provisioning and deprovisioning automatically with customers' identity providers via SCIM.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Self-serve SSO setup$q$, $q$Let your B2B customers configure their own SSO connections through guided flows without requiring engineering support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$User impersonation for support$q$, $q$Safely impersonate a user for debugging or support purposes, with built-in guardrails and audit alerting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Configurable security policies$q$, $q$Enforce password policies, multi-factor authentication, and per-organization session controls.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Webhooks and Terraform provider$q$, $q$React to user and organization lifecycle events via webhooks, and manage auth configuration as code with a dedicated Terraform provider.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Self-service API keys$q$, $q$Let users and organizations generate their own API keys, which automatically invalidate if the associated account is blocked or deleted.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Purpose-built for B2B SaaS with organizations, roles, and permissions modeled as core concepts rather than add-ons$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Unlimited SSO connections included on paid plans with no per-connection fees, unlike some competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Generous free tier covering up to 10,500 monthly active users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Self-serve SSO and SCIM setup reduces engineering overhead when onboarding enterprise customers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Small team size (estimated under 10 employees) means less scale than larger, more established identity providers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Less brand recognition than major identity platforms like Auth0 or Okta, which may matter for enterprise procurement checklists$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$SCIM directory sync requires stepping up to the pricier Growth Plus plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$As a young, venture-backed startup, long-term product roadmap and company stability carry more uncertainty than incumbents$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$What is PropelAuth used for$q$, $q$PropelAuth is used by B2B SaaS companies to add authentication, organization management, and enterprise features like SSO and SCIM to their products without building it themselves.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$How much does PropelAuth cost$q$, $q$PropelAuth is free for up to 10,500 monthly active users. The Growth plan starts at 150 dollars per month, Growth Plus is 500 dollars per month, and Enterprise pricing is custom quoted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Does PropelAuth charge extra per SSO connection$q$, $q$No, all of PropelAuth's paid plans include unlimited enterprise SSO connections with no additional per-connection fees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Does PropelAuth support SCIM provisioning$q$, $q$Yes, SCIM directory sync is available starting on the Growth Plus plan, supporting providers like Okta, Microsoft Entra ID, OneLogin, and JumpCloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Who founded PropelAuth$q$, $q$PropelAuth was founded in 2021 and went through Y Combinator's Winter 2022 batch, raising roughly 3.09 million dollars from investors including Y Combinator, Tiger Global, and Soma Capital.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Can a user belong to multiple organizations in PropelAuth$q$, $q$Yes, PropelAuth models organizations as a first-class concept, and a single user can belong to multiple organizations with different roles in each.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Where is PropelAuth headquartered$q$, $q$PropelAuth is headquartered in Redwood City, California, United States.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Does enabling SSO for a customer require code changes$q$, $q$No, PropelAuth is designed so that customers can self-configure their own SSO connections through guided setup flows without requiring code changes.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Enterprise-ready B2B SaaS onboarding$q$, $q$SaaS companies use PropelAuth to quickly offer SSO and SCIM to enterprise customers during procurement without building identity infrastructure in-house.$q$, $q$B2B SaaS startups and mid-market software companies selling to enterprise buyers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Multi-tenant organization management$q$, $q$Products with complex customer structures use PropelAuth's organization model to manage users who belong to multiple companies with different roles in each.$q$, $q$B2B platforms serving customers with multiple departments, teams, or partner organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Reducing engineering overhead on auth$q$, $q$Engineering teams offload authentication, session management, and enterprise identity features to PropelAuth instead of maintaining custom auth infrastructure.$q$, $q$Engineering teams at growing startups that want to focus on core product rather than auth infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Up to 10,500 monthly active users","Unlimited organizations","Custom domains and UI"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Growth$q$, $q$$150/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited enterprise SSO connections","User impersonation","Staging environment","API key management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Growth Plus$q$, $q$$500/month$q$, $q$Monthly$q$, NULL, $q$["SCIM directory sync","Advanced organization controls","Enhanced security options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual$q$, NULL, $q$["Custom SLAs and support","Advanced compliance options","Volume-based user pricing"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PropelAuth is a B2B-focused authentication and user management platform founded in 2021 and headquartered in Redwood City, California. The company went through Y Combinator's Winter 2022 batch and has raised roughly 3.09 million dollars from investors including Y Combinator, Tiger Global, and Soma Capital.$q$, $q$Unlike general-purpose identity platforms adapted for B2B use cases, PropelAuth is built from the ground up around the reality of B2B SaaS: customers are companies with many employees, different roles, and enterprise IT requirements like SSO and SCIM, not just individual end users.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Organizations are a first-class concept throughout PropelAuth: users can belong to multiple organizations with different roles in each, organizations can auto-join users via verified company email domains, and every authenticated request carries the user's organization membership, roles, and permissions.$q$, $q$Enterprise-readiness features, including SAML and OIDC SSO and SCIM directory provisioning for providers like Okta, Microsoft Entra ID, OneLogin, and JumpCloud, are deeply integrated rather than bolted on, and customers can self-configure their own SSO connections without requiring code changes from the PropelAuth customer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('789f97be-c510-457a-8f6f-591187e6b959', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PropelAuth's pricing is based on monthly active users (MAUs). The free tier covers up to 10,500 MAUs with unlimited organizations, while the Growth plan at 150 dollars per month adds unlimited enterprise SSO connections, user impersonation, a staging environment, and API key management.$q$, $q$A Growth Plus plan at 500 dollars per month adds SCIM directory sync and advanced organization and security controls, while Enterprise customers receive custom pricing. Notably, all paid plans include unlimited SSO connections with no per-connection fees.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$IDX and MLS-integrated websites$q$, $q$Lead-capture websites with real-time MLS listing synchronization built for real estate search and browsing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Automated lead routing$q$, $q$Route and assign new leads to agents automatically using round robin, auto-assign, or click-to-claim rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Integrated email marketing automation$q$, $q$Build segmented drip campaigns for nurture sequences, transaction-milestone updates, and broadcast communications.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Transaction management integration$q$, $q$Connects to Lone Wolf's broader transaction management and back-office software for end-to-end deal workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Pipeline and performance reporting$q$, $q$Track pipeline status, agent performance, and campaign attribution, with full custom Salesforce dashboards on the Salesforce Edition.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Native Salesforce customization$q$, $q$The Salesforce Edition is built directly on the Salesforce platform, giving access to Salesforce's full customization, workflow, and reporting ecosystem.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Mobile apps for agents$q$, $q$iOS and Android apps provide contact management, activity logging, calendar sync, and pipeline access for agents in the field.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Deep native Salesforce integration on the Salesforce Edition appeals to brokerages already invested in the Salesforce ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Backed by Lone Wolf Technologies' broader real estate software suite, including transaction management and back-office tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Strong IDX and MLS integration with real-time listing synchronization for lead generation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Established product with roots going back to 2010 and continued investment under Lone Wolf and Vista Equity Partners ownership$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Salesforce Edition requires a 10-user minimum at 79 dollars per user per month, which can be a significant upfront cost for small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Complexity and Salesforce dependency mean a steeper learning curve and potentially higher implementation and administration costs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Two distinct product lines (GO and Salesforce Edition) can create confusion about which version fits a given brokerage's size and needs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Ownership changes across three companies since 2010 (original Propertybase, Boston Logic, and Lone Wolf) mean product direction has shifted more than once$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Who owns Propertybase now$q$, $q$Propertybase is owned by Lone Wolf Technologies, a Vista Equity Partners portfolio company, which acquired Propertybase in August 2021. The product is now marketed as Propertybase powered by Lone Wolf.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$How much does Propertybase cost$q$, $q$Propertybase Salesforce Edition starts at 79 dollars per user per month with a 10-user minimum, putting the minimum monthly cost around 790 dollars. Propertybase GO uses separate, custom quote-based pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$What is the difference between Propertybase GO and Propertybase Salesforce Edition$q$, $q$Propertybase GO is a simplified CRM and website solution for brokerages and teams, while Propertybase Salesforce Edition is a more customizable, enterprise-class CRM built natively on the Salesforce platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$When was Propertybase founded$q$, $q$Propertybase was founded in 2010 and has since been acquired twice, first by Boston Logic in 2017 and then by Lone Wolf Technologies in 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Does Propertybase integrate with MLS listings$q$, $q$Yes, Propertybase includes IDX-enabled, MLS-integrated websites with real-time listing synchronization for lead capture.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Is Propertybase good for small real estate teams$q$, $q$The Salesforce Edition's 10-user minimum and per-seat pricing generally make it a better fit for mid-size and larger brokerages, while smaller teams are more often directed to the simplified Propertybase GO product.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Where is Propertybase's parent company headquartered$q$, $q$Lone Wolf Technologies, Propertybase's parent company, is headquartered in Cambridge, Ontario, Canada, with a significant office presence in Dallas, Texas.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Does Propertybase have mobile apps$q$, $q$Yes, Propertybase offers iOS and Android apps that give agents contact management, activity logging, calendar sync, and pipeline access on mobile.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Enterprise brokerage CRM on Salesforce$q$, $q$Larger brokerages already invested in the Salesforce ecosystem use Propertybase Salesforce Edition for deep CRM customization, reporting, and workflow automation.$q$, $q$Mid-size to large real estate brokerages using or wanting Salesforce-native infrastructure$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Lead generation and routing at scale$q$, $q$Brokerages use Propertybase's IDX-integrated websites and automated lead routing to capture and distribute leads to agents efficiently.$q$, $q$Brokerages and teams focused on high-volume online lead generation$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$End-to-end transaction workflow$q$, $q$Organizations already using Lone Wolf's transaction management and back-office tools extend that workflow into CRM and marketing with Propertybase.$q$, $q$Brokerages standardized on the broader Lone Wolf real estate technology suite$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Propertybase GO$q$, $q$Custom quote$q$, $q$Annual or monthly (quote-based)$q$, NULL, $q$["Simplified CRM and website builder","IDX/MLS integration","Lead capture and routing","Mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$Propertybase Salesforce Edition$q$, $q$From $79/user/month (10-user minimum)$q$, $q$Monthly, quarterly, or annual$q$, NULL, $q$["Native Salesforce customization","Advanced reporting and dashboards","Transaction management integration","Email marketing automation"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Propertybase is a real estate CRM platform originally founded in 2010 that changed ownership twice: acquired by Boston Logic in 2017, and then acquired outright by Lone Wolf Technologies, a Vista Equity Partners portfolio company, in August 2021. It is now marketed as Propertybase powered by Lone Wolf.$q$, $q$The product line includes two distinct offerings: Propertybase GO, a simplified CRM and website solution for brokerages and teams, and Propertybase Salesforce Edition, an enterprise-class CRM built natively on the Salesforce platform for larger, more customization-hungry organizations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Propertybase centers on IDX and MLS-integrated websites with real-time listing sync for lead capture, paired with automated lead routing and matching rules such as round robin, auto-assign, and click-to-claim to get new leads to the right agent quickly.$q$, $q$Beyond lead generation, the platform includes integrated email marketing with segmentation and drip automation, transaction management integration with Lone Wolf's back-office systems, pipeline and agent-performance reporting, and native mobile apps for iOS and Android that give agents contact management and deal pipeline visibility on the go.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('37206632-9f9a-460f-8492-df6a397cf34f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Propertybase Salesforce Edition requires a minimum of 10 user licenses at 79 dollars per user per month, which includes the underlying Force.com platform license, putting the effective minimum monthly cost at around 790 dollars for a brokerage's first 10 seats.$q$, $q$Propertybase GO, the simplified CRM and website product, is priced separately on a custom, quote basis rather than published per-seat pricing, and is generally positioned as the more accessible entry point for smaller brokerages and teams.$q$]::text[], 2);
